class Solution:
    def divide(self, dividend: int, divisor: int) -> int:
        if dividend == -2**31 and divisor == -1: return 2**31 - 1
        sign = -1 if (dividend < 0) ^ (divisor < 0) else 1
        a, b, q = abs(dividend), abs(divisor), 0
        while a >= b:
            k = 1
            while a >= (b << (k+1)): k += 1
            a -= b << k; q += 1 << k
        q *= sign
        return max(-2**31, min(2**31-1, q))

