class Solution {
public:
    int divide(int dividend, int divisor) {
        if (dividend == INT_MIN && divisor == -1) return INT_MAX;
        long sign = ((dividend < 0) ^ (divisor < 0)) ? -1 : 1;
        long a = labs(dividend), b = labs(divisor), q = 0;
        while (a >= b) {
            long k = 1;
            while (a >= (b << (k+1))) k <<= 1;
            a -= b << k; q += 1 << k;
        }
        q *= sign;
        return (int)max((long)INT_MIN, min((long)INT_MAX, q));
    }
};

